int do_for_each_ref_iterator(struct ref_iterator *iter,
			     refs_for_each_cb fn, void *cb_data)
{
	int retval = 0, ok;

	while ((ok = ref_iterator_advance(iter)) == ITER_OK) {
		retval = fn(&iter->ref, cb_data);
		if (retval)
			goto out;
	}

out:
